// Using the component
function App() {
  return (
    <Profile 
      {{name}}="John Doe"
      {{age}}={30}
      {{city}}="New York"
    />
  );
}

// Defining the component
function Profile({{props}}) {
  return (
    <div>
      <h2>{{props.name}}</h2>
      <p>Age: {{props.age}}</p>
      <p>Lives in: {{props.city}}</p>
    </div>
  );
}

